#!/usr/bin/env node
/**
 * Preserve a few compact, concrete examples requested by learner feedback in
 * pages which are regenerated by their track generators.
 * SPDX-License-Identifier: Apache-2.0
 */
import { readFileSync, writeFileSync } from "node:fs";
import { join, resolve } from "node:path";
import { fileURLToPath } from "node:url";

const root = resolve(join(fileURLToPath(import.meta.url), "..", ".."));
const replacements = [
  ["tracks/active-rpg/gauge-race", "actor.gauge += actor.speed\nif actor.gauge &gt;= maxGauge { actor.ready = true }", "actor.gauge += actor.speed\nif actor.gauge &gt;= maxGauge {\n    actor.gauge = 0\n    actor.ready = true\n}"],
  ["tracks/active-rpg/ready-queue", "readyQueue = append(readyQueue, actorID)\nactorID = readyQueue[0]", "readyQueue = append(readyQueue, actorID)\nactorID = readyQueue[0]\nreadyQueue = readyQueue[1:]"],
  ["tracks/rhythm/falling-notes", "// internal/rhythmplay: chart data enters the shared runner\nsession := NewSession(chart)", "// Schedule Beat and Lane before the game starts.\ncues := rhythmplay.Taps([]int{0, 1, 0, 2}, 0.5)\nchart := rhythmplay.MakeChart(\"SHRIMP STEP\", 108, 4, cues...)\n// Update advances session.Frame; Draw maps note.At - Frame to y."],
];

let changed = 0;
for (const language of ["ja", "en"]) {
  for (const [route, before, after] of replacements) {
    const file = join(root, "web", language, route, "index.html");
    const html = readFileSync(file, "utf8");
    const next = html.replace(before, after);
    if (next !== html) {
      writeFileSync(file, next);
      changed++;
    }
  }
}
console.log(`Injected ${changed} feedback-driven code examples.`);
